import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Languages, Bell, Check, Trash2, Cpu, Info, ChevronRight, Zap, ShieldCheck } from 'lucide-react';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';
import EnableNotificationsModal from './EnableNotificationsModal';
import { APP_VERSION } from '../constants';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose }) => {
  const { t, language, setLanguage } = useTranslation();
  const { addNotification } = useNotification();
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const [isEnableNotificationsModalOpen, setIsEnableNotificationsModalOpen] = useState(false);
  const [perfMode, setPerfMode] = useState(() => localStorage.getItem('flkrd_perf_mode') === 'true');

  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }
  }, [isOpen]);

  const handleNotificationRequest = async () => {
    if (!('Notification' in window)) {
        addNotification({ type: 'error', title: t('notificationsErrorTitle'), message: t('notificationsNotSupported') });
        return;
    }
    if (permission === 'denied') {
        setIsEnableNotificationsModalOpen(true);
        return;
    }
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
        addNotification({ type: 'success', title: t('notificationsSuccessTitle'), message: t('notificationsEnabled') });
    }
  };

  const handleClearCache = () => {
    if (confirm("Are you sure? This will clear your Watchlist and History.")) {
        localStorage.clear();
        addNotification({ type: 'info', title: 'System Purge', message: t('cacheCleared') });
        setTimeout(() => window.location.reload(), 1500);
    }
  };

  const togglePerfMode = () => {
    const newVal = !perfMode;
    setPerfMode(newVal);
    localStorage.setItem('flkrd_perf_mode', String(newVal));
  };

  const calculateStorage = () => {
    let total = 0;
    for (let x in localStorage) {
      if (localStorage.hasOwnProperty(x)) {
        total += ((localStorage[x].length + x.length) * 2);
      }
    }
    return (total / 1024).toFixed(2) + " KB";
  };

  const SettingRow = ({ icon, label, sublabel, action, value, isToggle = false }: any) => (
    <div className="flex items-center justify-between py-3 md:py-4 border-b border-white/5 last:border-0">
      <div className="flex items-center gap-3 md:gap-4 flex-1 min-w-0">
        <div className="p-2 bg-white/5 rounded-xl text-gray-400 group-hover:text-red-500 transition-colors">
          {icon}
        </div>
        <div className="flex flex-col min-w-0">
          <p className="text-[11px] md:text-sm font-black uppercase tracking-widest text-white truncate">{label}</p>
          {sublabel && <p className="text-[9px] md:text-xs text-gray-500 font-bold italic truncate">{sublabel}</p>}
        </div>
      </div>
      <div className="flex items-center gap-3">
        {isToggle ? (
            <button 
                onClick={action}
                className={`w-10 h-5 rounded-full p-1 transition-colors ${value ? 'bg-red-600' : 'bg-white/10'}`}
            >
                <motion.div animate={{ x: value ? 20 : 0 }} className="w-3 h-3 bg-white rounded-full shadow-sm" />
            </button>
        ) : action ? (
            <button onClick={action} className="text-gray-500 hover:text-white"><ChevronRight size={18} /></button>
        ) : (
            <span className="text-[10px] font-black text-red-500 uppercase">{value}</span>
        )}
      </div>
    </div>
  );

  return (
    <>
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/80 backdrop-blur-xl z-[100] flex items-end md:items-center justify-center p-4"
          >
            <motion.div
              initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
              transition={{ type: "spring", stiffness: 300, damping: 30 }}
              onClick={e => e.stopPropagation()}
              className="w-full max-w-lg bg-[#0c0c0c] border border-white/10 rounded-t-[2.5rem] md:rounded-[3rem] overflow-hidden shadow-2xl relative"
            >
              <div className="absolute top-0 left-0 w-full h-1 bg-red-600" />

              <div className="p-6 md:p-10">
                <div className="flex items-center justify-between mb-8">
                  <div>
                    <h2 className="text-2xl md:text-4xl font-[1000] uppercase italic tracking-tighter text-white">{t('settings')}</h2>
                    <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Configuration Panel</p>
                  </div>
                  <button onClick={onClose} className="p-3 bg-white/5 rounded-2xl hover:bg-red-600 transition-colors">
                    <X size={20} />
                  </button>
                </div>

                <div className="space-y-2">
                  <div className="mb-4">
                    <p className="text-[9px] font-black text-gray-600 uppercase tracking-[0.4em] mb-4">Interface & Language</p>
                    <div className="bg-white/\[0\.02\] rounded-3xl p-2 border border-white/5">
                        <div className="flex p-1 bg-black/40 rounded-2xl border border-white/5 mb-2">
                            <button onClick={() => setLanguage('en')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${language === 'en' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}>{t('english')}</button>
                            <button onClick={() => setLanguage('ku')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${language === 'ku' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-500 hover:text-white'}`}>{t('kurdish')}</button>
                        </div>
                        <SettingRow 
                            icon={<Bell size={18}/>} 
                            label={t('notifications')} 
                            sublabel={permission === 'granted' ? t('notificationsStatusEnabled') : t('notificationsStatusBlocked')}
                            action={handleNotificationRequest}
                        />
                    </div>
                  </div>

                  <div className="mb-4">
                    <p className="text-[9px] font-black text-gray-600 uppercase tracking-[0.4em] mb-4">{t('appTools')}</p>
                    <div className="bg-white/\[0\.02\] rounded-3xl p-4 border border-white/5 space-y-1">
                        <SettingRow icon={<Cpu size={18}/>} label={t('performanceMode')} sublabel={t('performanceModeDesc')} isToggle={true} value={perfMode} action={togglePerfMode} />
                        <SettingRow icon={<Trash2 size={18}/>} label={t('clearCache')} sublabel={t('clearCacheDesc')} action={handleClearCache} />
                        <SettingRow icon={<Zap size={18}/>} label={t('storageUsed')} value={calculateStorage()} />
                    </div>
                  </div>

                  <div>
                    <p className="text-[9px] font-black text-gray-600 uppercase tracking-[0.4em] mb-4">Identity</p>
                    <div className="bg-white/\[0\.02\] rounded-3xl p-4 border border-white/5 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-full bg-red-600/10 flex items-center justify-center text-red-600 border border-red-600/20">
                                <ShieldCheck size={20} />
                            </div>
                            <div className="flex flex-col">
                                <span className="text-[10px] font-black text-white uppercase">{t('appVersion')}</span>
                                <span className="text-[9px] font-bold text-gray-500 italic">Stable Build {APP_VERSION}</span>
                            </div>
                        </div>
                        <div className="bg-green-500/10 px-3 py-1 rounded-lg border border-green-500/20">
                            <span className="text-[8px] font-black text-green-500 uppercase tracking-widest">Linked</span>
                        </div>
                    </div>
                  </div>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
      <EnableNotificationsModal isOpen={isEnableNotificationsModalOpen} onClose={() => setIsEnableNotificationsModalOpen(false)} />
    </>
  );
};

export default SettingsModal;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { X, Plus, Check, Play, Trash2, AlertCircle, Loader2 } from 'lucide-react';
import { Content, WatchProgress, MyListItem } from '../types';
import { fetchData } from '../services/tmdbService';
import { IMAGE_BASE_URL_POSTER } from '../constants';
import Spinner from './Spinner';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';

interface RowProps {
  title: string;
  fetchUrl?: string;
  type?: 'movie' | 'tv';
  items?: (Content | WatchProgress | MyListItem)[];
  isProgressRow?: boolean;
}

const Row: React.FC<RowProps> = ({ title, fetchUrl, type, items, isProgressRow }) => {
  const [content, setContent] = useState<(Content | WatchProgress | MyListItem)[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [hasError, setHasError] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [myListIds, setMyListIds] = useState<Set<number>>(new Set());
  const [isPerfMode, setIsPerfMode] = useState(() => localStorage.getItem('flkrd_perf_mode') === 'true');

  const navigate = useNavigate();
  const rowRef = useRef<HTMLDivElement>(null);
  const { language, t } = useTranslation();
  const { addNotification } = useNotification();

  const updateMyListIds = useCallback(() => {
    const myList = JSON.parse(localStorage.getItem('myList') || '[]');
    setMyListIds(new Set(myList.map((item: any) => item.id)));
  }, []);

  const getPagedUrl = (baseUrl: string, pageNum: number) => {
    const connector = baseUrl.includes('?') ? '&' : '?';
    return `${baseUrl}${connector}page=${pageNum}`;
  };

  const loadInitialData = async () => {
    updateMyListIds();
    setHasError(false);
    if (items) {
      setContent(items);
      setLoading(false);
      setHasMore(false);
    } else if (fetchUrl) {
      setLoading(true);
      const data = await fetchData(getPagedUrl(fetchUrl, 1), language);
      if (data && Array.isArray(data) && data.length > 0) {
        setContent(data);
        setPage(1);
        setHasMore(data.length >= 19); 
      } else if (data === null) {
        setHasError(true);
      } else {
        setContent([]);
        setHasMore(false);
      }
      setLoading(false);
    }
  };

  useEffect(() => {
    loadInitialData();
    window.addEventListener('storage', updateMyListIds);
    return () => window.removeEventListener('storage', updateMyListIds);
  }, [fetchUrl, items, language, updateMyListIds]);

  const handleToggleMyList = (e: React.MouseEvent, item: any, mediaType: 'movie' | 'tv') => {
    e.stopPropagation();
    let myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
    const index = myList.findIndex(i => i.id === item.id);

    if (index > -1) {
      myList.splice(index, 1);
      addNotification({ type: 'info', title: t('notificationsInfoTitle'), message: t('myListRemoveSuccess') });
    } else {
      myList.push({ 
        id: item.id, 
        media_type: mediaType, 
        title: item.title || item.name || '', 
        poster_path: item.poster_path 
      });
      addNotification({ type: 'success', title: t('notificationsSuccessTitle'), message: t('myListAddSuccess') });
    }

    localStorage.setItem('myList', JSON.stringify(myList));
    updateMyListIds();
    window.dispatchEvent(new Event('storage'));
  };

  const handleRemoveProgress = (e: React.MouseEvent, id: number, mediaType: string) => {
      e.stopPropagation();
      const progress = JSON.parse(localStorage.getItem('watchProgress') || '[]');
      const filtered = progress.filter((item: any) => !(item.id === id && String(item.type) === mediaType));
      localStorage.setItem('watchProgress', JSON.stringify(filtered));
      setContent(prev => prev.filter(item => !(item.id === id && (item as any).type === mediaType)));
      window.dispatchEvent(new Event('storage'));
      window.dispatchEvent(new Event('watchProgressUpdated'));

      addNotification({ 
        type: 'info', 
        title: 'Archive Protocol', 
        message: t('removeFromProgress') 
      });
  };

  const handleScroll = useCallback(async () => {
    if (rowRef.current && fetchUrl && hasMore && !loadingMore) {
        const { scrollLeft, scrollWidth, clientWidth } = rowRef.current;
        const isNearEnd = scrollWidth - scrollLeft - clientWidth < 600;

        if (isNearEnd) {
            setLoadingMore(true);
            const nextPage = page + 1;
            const data = await fetchData(getPagedUrl(fetchUrl, nextPage), language);
            if (data && Array.isArray(data) && data.length > 0) {
                setContent(prev => {
                    const existingIds = new Set(prev.map(i => i.id));
                    const uniqueNewItems = data.filter(i => !existingIds.has(i.id));
                    return [...prev, ...uniqueNewItems];
                });
                setPage(nextPage);
                if (data.length < 15) setHasMore(false);
            } else {
                setHasMore(false);
            }
            setLoadingMore(false);
        }
    }
  }, [fetchUrl, hasMore, loadingMore, page, language]);

  const navigateToDetail = (item: any) => {
    const mType = item.media_type || (item as WatchProgress).type || type;
    if (mType === 'dubbed') {
      navigate(`/dubbed-details/${item.id}`);
    } else {
      navigate(`/details/${mType}/${item.id}`);
    }
  };

  if (loading) return <div className="h-32 md:h-52 flex items-center justify-center"><Spinner size="sm" /></div>;
  if (hasError || !content || content.length === 0) return null;

  const isKurdish = language === 'ku';

  return (
    <div className="mb-4 md:mb-10 px-4 md:px-8 relative z-20 overflow-hidden">
      {title && (
        <div className="flex items-center justify-between mb-3 md:mb-5">
            <h2 className={`text-sm md:text-xl font-[1000] flex items-center uppercase text-white ${!isKurdish ? 'italic tracking-tighter' : ''}`}>
                <span className="w-1 h-4 md:h-6 bg-red-600 rounded-full me-2 md:me-3 shadow-[0_0_10px_#e50914]"></span>
                {title}
            </h2>
            <button className="text-[9px] font-black text-red-600 uppercase tracking-widest hover:underline decoration-2 underline-offset-4">
                {t('seeMore')}
            </button>
        </div>
      )}
      <div className="relative group">
        <div 
          ref={rowRef} 
          onScroll={handleScroll} 
          className="flex overflow-x-scroll scrollbar-hide space-x-2.5 md:space-x-4 py-2 px-0.5 scroll-smooth"
        >
          {content.map((item, index) => {
              const mediaType = (item as Content).media_type || (item as WatchProgress).type || type;
              if (!item.poster_path || !mediaType) return null;
              const isAdded = myListIds.has(item.id);
              const hasProgress = 'progress' in item;
              const progressPct = hasProgress ? Math.min(100, ((item as WatchProgress).progress / ((item as WatchProgress).duration || 3600)) * 100) : 0;

              return (
              <motion.div
                key={`${item.id}-${index}-${mediaType}`}
                onClick={() => navigateToDetail(item)}
                className="flex-shrink-0 w-[110px] md:w-48 group/card relative cursor-pointer"
                whileTap={{ scale: 0.95 }}
                initial={isPerfMode ? { opacity: 1 } : { opacity: 0, x: 10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: isPerfMode ? 0 : (index % 6) * 0.04 }}
              >
                <div className="relative rounded-lg md:rounded-2xl overflow-hidden border border-white/5 shadow-lg transition-all duration-300 md:group-hover/card:border-red-600/40">
                  <img
                    src={item.poster_path.startsWith('http') ? item.poster_path : `${IMAGE_BASE_URL_POSTER}${item.poster_path}`}
                    alt={(item as Content).title || (item as Content).name}
                    className="object-cover w-full h-full transition-transform duration-500 md:group-hover/card:scale-105"
                    loading="lazy"
                  />

                  <div className="absolute top-1 right-1 flex flex-col gap-1 z-30 opacity-0 group-hover/card:opacity-100 transition-opacity">
                      {!isProgressRow && (
                        <button
                          onClick={(e) => handleToggleMyList(e, item, mediaType as 'movie' | 'tv')}
                          className={`p-1 rounded-md backdrop-blur-xl border transition-all ${isAdded ? 'bg-red-600 border-red-500 text-white' : 'bg-black/60 border-white/10 text-white hover:bg-red-600'}`}
                        >
                          {isAdded ? <Check size={12} strokeWidth={4} /> : <Plus size={12} strokeWidth={4} />}
                        </button>
                      )}
                  </div>

                  {hasProgress && (
                      <div className="absolute bottom-0 left-0 right-0 h-1 bg-black/60 z-20">
                          <div className="h-full bg-red-600 shadow-[0_0_8px_#e50914]" style={{ width: `${progressPct}%` }} />
                      </div>
                  )}

                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent opacity-0 md:group-hover/card:opacity-100 transition-opacity flex flex-col justify-end p-2 md:p-4">
                      <div className="flex items-center gap-1.5 translate-y-2 group-hover/card:translate-y-0 transition-transform duration-300">
                          <div className="bg-red-600 p-1 rounded-full"><Play size={8} fill="white" className="text-white ml-0.5" /></div>
                          <span className="text-[8px] font-black uppercase tracking-wider text-white italic">{hasProgress ? 'Resume' : 'Play'}</span>
                      </div>
                  </div>
                </div>
              </motion.div>
            )}
          )}

          {hasMore && (
            <div className="flex-shrink-0 w-16 md:w-32 flex items-center justify-center">
                {loadingMore ? <Loader2 size={24} className="text-red-600 animate-spin" /> : <div className="w-1 h-8 bg-white/5 rounded-full" />}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Row;

import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useTranslation } from '../contexts/LanguageContext';
import { Cog, Moon, Sun, PlayCircle, User } from 'lucide-react';
import SettingsModal from './SettingsModal';

const Header: React.FC<{ scrolled: boolean }> = () => {
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'dark';
  });
  const { t } = useTranslation();
  const navigate = useNavigate();

  useEffect(() => {
    localStorage.setItem('theme', theme);
    if (theme === 'light') {
      document.documentElement.classList.add('light-mode');
    } else {
      document.documentElement.classList.remove('light-mode');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  return (
    <>
      <header className={`fixed top-0 left-0 right-0 z-40 p-2 sm:p-4 lg:p-6 flex items-center justify-between pointer-events-none transition-all duration-300`}>
        <Link to="/" className="pointer-events-auto">
          <div className="flex items-center gap-1.5 bg-black/40 backdrop-blur-xl border border-white/10 rounded-lg p-1 md:p-1.5 transition-all shadow-xl active:scale-95">
            <img src="https://i.imgur.com/DF1UZL3.png" alt="FLKRD" className="h-5 md:h-8 object-contain" />
            <h1 className="text-[10px] md:text-lg font-black text-red-600 tracking-tighter pr-1 hidden md:block">FLKRD MOVIES</h1>
          </div>
        </Link>
        <div className="flex items-center space-x-1.5 md:space-x-2 pointer-events-auto">
          <button
            onClick={() => navigate('/continue-watching')}
            className="hidden lg:flex items-center gap-1.5 bg-red-600 hover:bg-red-700 text-white px-3 py-1.5 rounded-xl font-black text-[9px] uppercase tracking-widest shadow-lg transition-all"
            aria-label={t('continueWatching')}
          >
            <PlayCircle size={14} fill="white" className="text-red-600" />
            <span className="italic">{t('continueWatching')}</span>
          </button>

          <button
            onClick={toggleTheme}
            className="bg-black/40 backdrop-blur-xl border border-white/10 rounded-full w-8 h-8 md:w-10 md:h-10 flex items-center justify-center transition-all shadow-lg active:scale-90"
            aria-label="Toggle Theme"
          >
            {theme === 'dark' ? <Sun size={14} className="text-yellow-400 md:w-5 md:h-5" /> : <Moon size={14} className="text-indigo-600 md:w-5 md:h-5" />}
          </button>

          <button
            onClick={() => navigate('/profile')}
            className="bg-red-600/20 backdrop-blur-xl border border-red-600/30 rounded-full w-8 h-8 md:w-10 md:h-10 flex items-center justify-center transition-all shadow-lg hover:bg-red-600 group active:scale-90"
            aria-label={t('profile')}
          >
            <User size={14} className="text-red-500 md:w-5 md:h-5 group-hover:text-white transition-colors" />
          </button>

          <button
            onClick={() => setIsSettingsOpen(true)}
            className="bg-black/40 backdrop-blur-xl border border-white/10 rounded-full w-8 h-8 md:w-10 md:h-10 flex items-center justify-center transition-all shadow-lg active:scale-90"
            aria-label={t('settings')}
          >
            <Cog size={14} className="text-gray-400 md:w-5 md:h-5" />
          </button>
        </div>
      </header>
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} />
    </>
  );
};

export default Header;

