    <div className="fixed bottom-3 left-1/2 -translate-x-1/2 z-50 md:hidden w-[94%] max-w-sm">
      <div className="flex items-center justify-around bg-black/50 backdrop-blur-2xl rounded-2xl px-1 py-1 shadow-2xl border border-white/10">
