export default MobileNav;

import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Play, X, Zap, Activity, Trash2, ChevronRight, ChevronLeft, History } from 'lucide-react';
import { WatchProgress } from '../types';
import { IMAGE_BASE_URL_POSTER } from '../constants';
import { useTranslation } from '../contexts/LanguageContext';

const ContinueWatchingPortal: React.FC = () => {
  const [items, setItems] = useState<WatchProgress[]>([]);
  const [isExpanded, setIsExpanded] = useState(false);
  const [currentIndex, setCurrentIndex] = useState(0);

  const navigate = useNavigate();
  const location = useLocation();
  const { t } = useTranslation();

  const isExcludedPage = location.pathname.includes('/shorts') || location.pathname.includes('/search');

  const loadProgressHistory = useCallback(() => {
    try {
      const progressData = localStorage.getItem('watchProgress');
      if (!progressData) {
        setItems([]);
        return;
      }

      const progress: WatchProgress[] = JSON.parse(progressData);
      const unfinished = progress
        .filter(item => {
            const duration = item.duration || 3600;
            return item.progress > 10 && item.progress < duration * 0.98;
        })
        .sort((a, b) => (b.lastWatched || 0) - (a.lastWatched || 0));

      setItems(unfinished);
      if (currentIndex >= unfinished.length) setCurrentIndex(0);
    } catch (e) {}
  }, [currentIndex]);

  useEffect(() => {
    loadProgressHistory();
    const syncHandler = () => loadProgressHistory();
    window.addEventListener('storage', syncHandler);
    window.addEventListener('watchProgressUpdated', syncHandler);
    const interval = setInterval(loadProgressHistory, 10000);
    return () => {
      window.removeEventListener('storage', syncHandler);
      window.removeEventListener('watchProgressUpdated', syncHandler);
      clearInterval(interval);
    };
  }, [loadProgressHistory]);

  const handleRemove = (e: React.MouseEvent, targetItem: WatchProgress) => {
    e.stopPropagation();
    const progress: WatchProgress[] = JSON.parse(localStorage.getItem('watchProgress') || '[]');
    const updated = progress.filter(i => !(i.id === targetItem.id && String(i.type) === String(targetItem.type)));
    localStorage.setItem('watchProgress', JSON.stringify(updated));
    if (items.length <= 1) setIsExpanded(false);
    loadProgressHistory();
    window.dispatchEvent(new Event('storage'));
  };

  const handleResume = (item: WatchProgress) => {
    if (String(item.type) === 'dubbed') navigate(`/dubbed-details/${item.id}`);
    else navigate(`/details/${item.type}/${item.id}`);
    setIsExpanded(false);
  };

  if (items.length === 0 || isExcludedPage) return null;

  const activeItem = items[currentIndex] || items[0];
  const progressPercent = Math.min(100, (activeItem.progress / (activeItem.duration || 1)) * 100);

  return (
    <div className="fixed bottom-16 right-3 md:bottom-8 md:right-8 z-[100] pointer-events-none">
      <div className="relative flex flex-col items-end pointer-events-auto">

        <AnimatePresence>
          {isExpanded && (activeItem) && (
            <motion.div
              initial={{ opacity: 0, scale: 0.9, y: 15 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.9, y: 15 }}
              className="mb-3 w-[260px] md:w-[320px] bg-[#0c0c0c] border border-white/10 rounded-[2rem] p-4 shadow-2xl overflow-hidden"
            >
              <div className="absolute top-0 left-0 w-full h-0.5 bg-red-600" />

              <div className="relative z-10">
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-1.5">
                    <Activity size={10} className="text-red-600 animate-pulse" />
                    <span className="text-[8px] font-black uppercase tracking-widest text-gray-500">RESUME {currentIndex + 1}/{items.length}</span>
                  </div>
                  <button onClick={() => setIsExpanded(false)} className="text-gray-500 hover:text-white"><X size={14} /></button>
                </div>

                <div className="flex gap-3 mb-4">
                    <div className="w-14 h-20 rounded-xl overflow-hidden flex-shrink-0 border border-white/5 bg-black">
                        <img src={activeItem.poster_path?.startsWith('http') ? activeItem.poster_path : `${IMAGE_BASE_URL_POSTER}${activeItem.poster_path}`} className="w-full h-full object-cover" alt="" />
                    </div>
                    <div className="min-w-0 flex-1 flex flex-col justify-center">
                        <h4 className="text-white text-sm font-black uppercase italic truncate">{activeItem.title}</h4>
                        <p className="text-[8px] font-black text-red-500 uppercase mt-1">{Math.floor(progressPercent)}% Sync</p>
                        <div className="w-full h-1 bg-white/5 rounded-full mt-2 overflow-hidden">
                             <motion.div animate={{ width: `${progressPercent}%` }} className="h-full bg-red-600" />
                        </div>
                    </div>
                </div>

                <div className="flex gap-2">
                  <button onClick={() => handleResume(activeItem)} className="flex-1 bg-white text-black py-2 rounded-lg font-black text-[9px] uppercase tracking-widest italic flex items-center justify-center gap-1.5 hover:bg-red-600 hover:text-white transition-all">
                    <Play size={10} fill="currentColor" /> STREAM
                  </button>
                  <button onClick={(e) => handleRemove(e, activeItem)} className="px-3 bg-red-600/10 text-red-600 rounded-lg border border-red-600/20"><Trash2 size={14}/></button>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <motion.button 
          whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }} onClick={() => setIsExpanded(!isExpanded)} 
          className="relative w-12 h-12 md:w-14 md:h-14 rounded-full shadow-2xl"
        >
          <svg className="absolute inset-0 w-full h-full -rotate-90 z-20 pointer-events-none">
            <circle cx="50%" cy="50%" r="42%" className="stroke-white/10 fill-transparent" strokeWidth="2.5" />
            <motion.circle cx="50%" cy="50%" r="42%" className="stroke-red-600" strokeWidth="2.5" fill="none" strokeDasharray="100 100" animate={{ strokeDashoffset: 100 - (activeItem ? progressPercent : 0) }} />
          </svg>
          <div className="absolute inset-1 rounded-full overflow-hidden z-10 border border-white/10 bg-black">
            <div className="absolute inset-0 flex items-center justify-center">
               <div className={`p-2 rounded-full transition-all ${isExpanded ? 'bg-white text-black' : 'bg-red-600 text-white'}`}>
                  {isExpanded ? <X size={14} /> : <History size={14} />}
               </div>
            </div>
          </div>
        </motion.button>
      </div>
    </div>
  );
};

export default ContinueWatchingPortal;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Languages, Bell, Trash2, Cpu, Info, ChevronRight, Zap, ShieldCheck, RefreshCw, Activity, Code } from 'lucide-react';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';
import { APP_VERSION } from '../constants';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose }) => {
  const { t, language, setLanguage } = useTranslation();
  const { addNotification } = useNotification();
  const [isSyncing, setIsSyncing] = useState(false);
  const [networkLatency, setNetworkLatency] = useState<string | null>(null);
  const [debugMode, setDebugMode] = useState(() => localStorage.getItem('flkrd_debug') === 'true');
  const [perfMode, setPerfMode] = useState(() => localStorage.getItem('flkrd_perf_mode') === 'true');

  const handleSyncNodes = () => {
    setIsSyncing(true);
    setTimeout(() => {
        setIsSyncing(false);
        addNotification({ type: 'success', title: 'Neural Sync', message: t('syncComplete') });
        window.dispatchEvent(new Event('storage'));
    }, 2000);
  };

  const checkNetwork = async () => {
    const start = Date.now();
    setNetworkLatency('Testing...');
    try {
        await fetch('https://api.themoviedb.org/3/configuration?api_key=39ad6c4210f7e4357f3b5762fcaeb1db');
        const end = Date.now();
        setNetworkLatency(`${end - start}ms`);
        addNotification({ type: 'info', title: t('networkCheck'), message: t('networkOk') });
    } catch {
        setNetworkLatency('Offline');
        addNotification({ type: 'error', title: t('networkCheck'), message: t('networkFail') });
    }
  };

  const handleClearCache = () => {
    if (confirm("Wipe system data? (This resets Watchlist/History)")) {
        localStorage.clear();
        addNotification({ type: 'success', title: 'Wipe Complete', message: t('cacheCleared') });
        setTimeout(() => window.location.reload(), 1000);
    }
  };

  const toggleDebug = () => {
    const newVal = !debugMode;
    setDebugMode(newVal);
    localStorage.setItem('flkrd_debug', String(newVal));
    addNotification({ type: 'info', title: 'System', message: `Debug mode ${newVal ? 'Active' : 'Standby'}` });
  };

  const togglePerf = () => {
    const newVal = !perfMode;
    setPerfMode(newVal);
    localStorage.setItem('flkrd_perf_mode', String(newVal));
    window.location.reload(); // Refresh to apply animation changes
  };

  const SettingRow = ({ icon, label, sublabel, action, value, isToggle = false, isLoading = false }: any) => (
    <div className="flex items-center justify-between py-2 border-b border-white/5 last:border-0 group">
      <div className="flex items-center gap-3 flex-1 min-w-0">
        <div className="p-1.5 bg-white/5 rounded-lg text-gray-400 group-hover:text-red-500 transition-colors">
          {icon}
        </div>
        <div className="flex flex-col min-w-0">
          <p className="text-[10px] font-black uppercase tracking-wider text-white truncate">{label}</p>
          {sublabel && <p className="text-[8px] text-gray-500 font-bold truncate">{sublabel}</p>}
        </div>
      </div>
      <div className="flex items-center gap-2">
        {isToggle ? (
            <button 
                onClick={action}
                className={`w-8 h-4 rounded-full p-0.5 transition-colors ${value ? 'bg-red-600' : 'bg-white/10'}`}
            >
                <motion.div animate={{ x: value ? 16 : 0 }} className="w-3 h-3 bg-white rounded-full" />
            </button>
        ) : action ? (
            <button onClick={action} className="text-gray-500 hover:text-white">
                {isLoading ? <RefreshCw size={14} className="animate-spin text-red-500" /> : <ChevronRight size={14} />}
            </button>
        ) : (
            <span className="text-[9px] font-black text-red-500 uppercase">{value}</span>
        )}
      </div>
    </div>
  );

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
          onClick={onClose}
          className="fixed inset-0 bg-black/90 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-4"
        >
          <motion.div
            initial={{ y: 100, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 100, opacity: 0 }}
            onClick={e => e.stopPropagation()}
            className="w-full max-w-sm bg-[#0a0a0a] border border-white/10 rounded-[2rem] overflow-hidden shadow-2xl"
          >
            <div className="h-1 w-full bg-red-600" />
            <div className="p-5">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h2 className="text-xl font-black uppercase italic tracking-tighter text-white">{t('settings')}</h2>
                  <p className="text-[8px] font-black text-gray-500 uppercase tracking-widest">Mainframe v{APP_VERSION}</p>
                </div>
                <button onClick={onClose} className="p-2 bg-white/5 rounded-xl hover:bg-red-600 transition-colors">
                  <X size={16} />
                </button>
              </div>

              <div className="space-y-6">
                <div>
                  <p className="text-[7px] font-black text-gray-600 uppercase tracking-[0.4em] mb-2">Region & Nodes</p>
                  <div className="bg-white/\[0\.02\] rounded-2xl p-3 border border-white/5 space-y-1">
                      <div className="flex gap-1 mb-2">
                        <button onClick={() => setLanguage('en')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${language === 'en' ? 'bg-red-600 text-white' : 'bg-black text-gray-500'}`}>ENG</button>
                        <button onClick={() => setLanguage('ku')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${language === 'ku' ? 'bg-red-600 text-white' : 'bg-black text-gray-500'}`}>KUR</button>
                      </div>
                      <SettingRow icon={<RefreshCw size={14}/>} label={t('systemSync')} sublabel={t('systemSyncDesc')} action={handleSyncNodes} isLoading={isSyncing} />
                      <SettingRow icon={<Activity size={14}/>} label={t('networkCheck')} value={networkLatency || '--'} action={checkNetwork} />
                  </div>
                </div>

                <div>
                  <p className="text-[7px] font-black text-gray-600 uppercase tracking-[0.4em] mb-2">{t('appTools')}</p>
                  <div className="bg-white/\[0\.02\] rounded-2xl p-3 border border-white/5 space-y-1">
                      <SettingRow icon={<Cpu size={14}/>} label={t('performanceMode')} sublabel={t('performanceModeDesc')} isToggle={true} value={perfMode} action={togglePerf} />
                      <SettingRow icon={<Code size={14}/>} label={t('debugMode')} sublabel={t('debugModeDesc')} isToggle={true} value={debugMode} action={toggleDebug} />
                      <SettingRow icon={<Trash2 size={14}/>} label={t('clearCache')} sublabel={t('clearCacheDesc')} action={handleClearCache} />
                  </div>
                </div>

                <div className="bg-red-600/5 p-4 rounded-2xl border border-red-600/10 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <ShieldCheck size={20} className="text-red-600" />
                        <div>
                            <p className="text-[9px] font-black text-white uppercase">{t('appVersion')}</p>
                            <p className="text-[8px] font-bold text-gray-500 italic">{t('nodeStable')}</p>
                        </div>
                    </div>
                    <span className="bg-green-600/20 text-green-500 text-[8px] font-black px-2 py-0.5 rounded-md border border-green-500/20 uppercase tracking-widest">Linked</span>
                </div>
              </div>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default SettingsModal;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Plus, Check, Play, Loader2, Info } from 'lucide-react';
import { Content, WatchProgress, MyListItem } from '../types';
import { fetchData } from '../services/tmdbService';
import { IMAGE_BASE_URL_POSTER } from '../constants';
import Spinner from './Spinner';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';

interface RowProps {
  title: string;
  fetchUrl?: string;
  type?: 'movie' | 'tv';
  items?: (Content | WatchProgress | MyListItem)[];
  isProgressRow?: boolean;
}

const Row: React.FC<RowProps> = ({ title, fetchUrl, type, items, isProgressRow }) => {
  const [content, setContent] = useState<(Content | WatchProgress | MyListItem)[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [myListIds, setMyListIds] = useState<Set<number>>(new Set());
  const [debugMode] = useState(() => localStorage.getItem('flkrd_debug') === 'true');

  const navigate = useNavigate();
  const rowRef = useRef<HTMLDivElement>(null);
  const { language, t } = useTranslation();
  const { addNotification } = useNotification();

  const updateMyListIds = useCallback(() => {
    const myList = JSON.parse(localStorage.getItem('myList') || '[]');
    setMyListIds(new Set(myList.map((item: any) => item.id)));
  }, []);

  useEffect(() => {
    const loadInitialData = async () => {
        updateMyListIds();
        if (items) {
          setContent(items);
          setLoading(false);
          setHasMore(false);
        } else if (fetchUrl) {
          setLoading(true);
          const data = await fetchData(`${fetchUrl}${fetchUrl.includes('?') ? '&' : '?'}page=1`, language);
          if (data && Array.isArray(data)) {
            setContent(data);
            setHasMore(data.length >= 10); 
          }
          setLoading(false);
        }
    };
    loadInitialData();
  }, [fetchUrl, items, language, updateMyListIds]);

  const handleToggleMyList = (e: React.MouseEvent, item: any, mediaType: 'movie' | 'tv') => {
    e.stopPropagation();
    let myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
    const index = myList.findIndex(i => i.id === item.id);
    if (index > -1) {
      myList.splice(index, 1);
    } else {
      myList.push({ id: item.id, media_type: mediaType, title: item.title || item.name || '', poster_path: item.poster_path });
    }
    localStorage.setItem('myList', JSON.stringify(myList));
    updateMyListIds();
    addNotification({ type: 'success', title: 'Vault', message: 'Library updated.' });
  };

  if (loading) return <div className="h-24 md:h-32 flex items-center justify-center"><Spinner size="sm" /></div>;
  if (!content || content.length === 0) return null;

  return (
    <div className="mb-6 px-4 md:px-8 relative z-20 overflow-hidden">
      <div className="flex items-center justify-between mb-2">
          <h2 className="text-[11px] md:text-sm font-black uppercase italic tracking-tighter text-white flex items-center gap-2">
              <span className="w-0.5 h-3 bg-red-600 rounded-full shadow-[0_0_10px_#e50914]"></span>
              {title}
          </h2>
          <button className="text-[8px] font-black text-gray-500 uppercase tracking-widest hover:text-red-500 transition-colors">
              {t('seeMore')}
          </button>
      </div>

      <div className="relative group">
        <div ref={rowRef} className="flex overflow-x-scroll scrollbar-hide space-x-2 py-1">
          {content.map((item, index) => {
              const mediaType = (item as Content).media_type || (item as WatchProgress).type || type || 'movie';
              if (!item.poster_path) return null;
              const isAdded = myListIds.has(item.id);
              const progressPct = 'progress' in item ? (item.progress / (item.duration || 1)) * 100 : 0;

              return (
              <motion.div
                key={`${item.id}-${index}`}
                onClick={() => navigate(`/details/${mediaType}/${item.id}`)}
                className="flex-shrink-0 w-[95px] md:w-40 group/card relative cursor-pointer"
                whileTap={{ scale: 0.95 }}
              >
                <div className="relative aspect-[2/3] rounded-lg overflow-hidden border border-white/5 shadow-2xl transition-all duration-300 md:group-hover/card:border-red-600/50">
                  <img
                    src={`${IMAGE_BASE_URL_POSTER}${item.poster_path}`}
                    alt=""
                    className="object-cover w-full h-full transition-transform duration-500 md:group-hover/card:scale-105"
                    loading="lazy"
                  />

                  {debugMode && (
                    <div className="absolute top-1 left-1 bg-black/80 p-0.5 rounded text-[6px] font-black text-white/50 z-30 uppercase">ID: {item.id}</div>
                  )}

                  <div className="absolute top-1 right-1 opacity-0 group-hover/card:opacity-100 transition-opacity z-30">
                      {!isProgressRow && (
                        <button
                          onClick={(e) => handleToggleMyList(e, item, mediaType as 'movie' | 'tv')}
                          className={`p-1 rounded-md transition-all ${isAdded ? 'bg-red-600 text-white' : 'bg-black/60 text-white hover:bg-red-600'}`}
                        >
                          {isAdded ? <Check size={10} strokeWidth={4} /> : <Plus size={10} strokeWidth={4} />}
                        </button>
                      )}
                  </div>

                  {progressPct > 0 && (
                      <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-black/60 z-20">
                          <div className="h-full bg-red-600" style={{ width: `${progressPct}%` }} />
                      </div>
                  )}

                  <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent opacity-0 md:group-hover/card:opacity-100 transition-opacity flex flex-col justify-end p-2">
                      <div className="flex items-center gap-1">
                          <div className="bg-red-600 p-1 rounded-full"><Play size={6} fill="white" className="ml-0.5" /></div>
                          <span className="text-[7px] font-black uppercase tracking-widest text-white italic">Stream</span>
                      </div>
                  </div>
                </div>
              </motion.div>
            )}
          )}
        </div>
      </div>
    </div>
  );
};

export default Row;

