import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Languages, Bell, Trash2, Cpu, Info, ChevronRight, Zap, ShieldCheck, RefreshCw, Activity, Code, Type, Layout, MousePointer2 } from 'lucide-react';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';
import { APP_VERSION } from '../constants';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose }) => {
  const { t, language, setLanguage } = useTranslation();
  const { addNotification } = useNotification();
  const [isSyncing, setIsSyncing] = useState(false);
  const [networkLatency, setNetworkLatency] = useState<string | null>(null);

  // Persistence for UI Scales
  const [textScale, setTextScale] = useState(() => Number(localStorage.getItem('flkrd_text_scale') || '1.0'));
  const [cardScale, setCardScale] = useState(() => Number(localStorage.getItem('flkrd_card_scale') || '1.0'));
  const [btnScale, setBtnScale] = useState(() => Number(localStorage.getItem('flkrd_btn_scale') || '1.0'));

  const [debugMode, setDebugMode] = useState(() => localStorage.getItem('flkrd_debug') === 'true');
  const [perfMode, setPerfMode] = useState(() => localStorage.getItem('flkrd_perf_mode') === 'true');

