            <button 
                onClick={action}
                className={`w-9 h-5 rounded-full p-0.5 transition-colors ${value ? 'bg-red-600' : 'bg-white/10'}`}
            >
                <motion.div animate={{ x: value ? 16 : 0 }} className="w-4 h-4 bg-white rounded-full" />
            </button>
        ) : action ? (
            <button onClick={action} className="text-gray-500 hover:text-white transition-colors">
                {isLoading ? <RefreshCw size={16} className="animate-spin text-red-500" /> : <ChevronRight size={16} />}
            </button>
        ) : (
            <span className="text-[10px] font-black text-red-500 uppercase">{value}</span>
        )}
      </div>
    </div>
);

