                        <p className="text-gray-200 text-xl md:text-3xl leading-relaxed italic font-bold">{content.overview}</p>
                    </div>

                    {cast.length > 0 && (
                      <div className="mb-24">
                        <div className="flex items-center gap-4 mb-12"><h2 className="text-3xl md:text-6xl font-[1000] uppercase italic tracking-tighter text-white">{language === 'ku' ? 'ئەکتەرەکان' : 'BIOMETRIC_DATA'}</h2><div className="h-[2px] flex-grow bg-white/5 rounded-full"></div></div>
                        <div className="grid grid-cols-3 sm:grid-cols-3 md:grid-cols-5 gap-4 md:gap-8">
                          {cast.map(person => (
