                              <div className="aspect-[3/4] rounded-xl md:rounded-[2.5rem] overflow-hidden mb-3 border border-white/5 shadow-2xl relative">
                                <img src={person.profile_path ? `${IMAGE_BASE_URL}${person.profile_path}` : 'https://i.imgur.com/4HoT8Yf.png'} alt="" className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 group-hover:scale-110" />
                              </div>
                              <p className="text-[10px] md:text-xs font-black uppercase italic truncate text-white">{person.name}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                </div>
                <div className="space-y-12">
                   <div className="bg-white/[0.02] border border-white/10 p-8 rounded-[2.5rem] shadow-2xl backdrop-blur-[60px]">
                        <h3 className="text-[10px] font-black uppercase tracking-[0.4em] mb-8 text-gray-500 italic">TRANSMISSION_NODES</h3>
                        <div className="grid grid-cols-2 gap-6">
                           {content.production_companies?.filter((c: any) => c.logo_path).slice(0, 4).map((company: any) => (
                               <div key={company.id} className="aspect-video bg-black/40 rounded-2xl p-5 flex items-center justify-center hover:bg-white transition-all duration-700 group/comp border border-white/5 shadow-inner">
                                   <img src={`${IMAGE_BASE_URL_LOGO}${company.logo_path}`} alt="" className="max-w-full max-h-full object-contain filter brightness-0 invert group-hover/comp:invert-0" />
                               </div>
                           ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
  );
};

