const TVDetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t, language } = useTranslation();
  const { addNotification } = useNotification();

  const [content, setContent] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [isPlayerLoading, setIsPlayerLoading] = useState(true);
  const [cast, setCast] = useState<CastMember[]>([]);
  const [recommendations, setRecommendations] = useState<Content[]>([]);
  const [isInMyList, setIsInMyList] = useState(false);
  const [isPlayerModalOpen, setIsPlayerModalOpen] = useState(false);
  const [selectedSeason, setSelectedSeason] = useState(1);
  const [selectedEpisode, setSelectedEpisode] = useState(1);
  const [seasonDetails, setSeasonDetails] = useState<SeasonDetails | null>(null);
  const [activeSource, setActiveSource] = useState('Vidking');
  const [showSourceSwitcher, setShowSourceSwitcher] = useState(false);
  const [watchedEpisodes, setWatchedEpisodes] = useState<Set<string>>(new Set());
  const [initialProgress, setInitialProgress] = useState(0);
  const [currentPlaybackTime, setCurrentPlaybackTime] = useState(0);
  const [currentPlaybackDuration, setCurrentPlaybackDuration] = useState(0);
  const [logoPath, setLogoPath] = useState<string | null>(null);
  const [trailerKey, setTrailerKey] = useState<string | null>(null);
  const [isTrailerModalOpen, setIsTrailerModalOpen] = useState(false);
  const [isMuted, setIsMuted] = useState(true);

  // Binge Mode Logic
  const [isBingeEnabled, setIsBingeEnabled] = useState(() => localStorage.getItem('flkrd_binge_mode') === 'true');
  const [showBingeCountdown, setShowBingeCountdown] = useState(false);
  const [countdown, setCountdown] = useState(10);
  const countdownTimerRef = useRef<number | null>(null);

  const sources = getRankedSources();

  const toggleBingeMode = () => {
    const newState = !isBingeEnabled;
    setIsBingeEnabled(newState);
    localStorage.setItem('flkrd_binge_mode', String(newState));
  };

  const playNextEpisode = useCallback(() => {
    if (!seasonDetails) return;
    const currentIdx = seasonDetails.episodes.findIndex(e => e.episode_number === selectedEpisode);
    const nextEp = seasonDetails.episodes[currentIdx + 1];

    if (nextEp) {
      setSelectedEpisode(nextEp.episode_number);
      setIsPlayerLoading(true);
      setShowBingeCountdown(false);
      setCountdown(10);
    } else {
      const nextSeasonNum = selectedSeason + 1;
      if (content?.number_of_seasons >= nextSeasonNum) {
          setSelectedSeason(nextSeasonNum);
          setSelectedEpisode(1);
          setIsPlayerLoading(true);
          setShowBingeCountdown(false);
          setCountdown(10);
          fetchSeasonDetails(nextSeasonNum);
      } else {
          setIsPlayerModalOpen(false);
          setShowBingeCountdown(false);
      }
    }
  }, [selectedEpisode, seasonDetails, selectedSeason, content]);

  useEffect(() => {
    if (showBingeCountdown && countdown > 0) {
      countdownTimerRef.current = window.setTimeout(() => setCountdown(prev => prev - 1), 1000);
    } else if (showBingeCountdown && countdown === 0) {
      playNextEpisode();
    }
    return () => { if (countdownTimerRef.current) clearTimeout(countdownTimerRef.current); };
  }, [showBingeCountdown, countdown, playNextEpisode]);

  const updateProgress = useCallback((data: any) => {
    if (!content) return;
    const progressData = localStorage.getItem('watchProgress');
    let progress: WatchProgress[] = progressData ? JSON.parse(progressData) : [];

    const time = data.currentTime || data.time;
    const duration = data.duration;

    setCurrentPlaybackTime(time);
    setCurrentPlaybackDuration(duration);

    const index = progress.findIndex(i => i.id === content.id && i.type === 'tv');
    const item: WatchProgress = {
      id: content.id,
      type: 'tv',
      title: content.name,
      poster_path: content.poster_path,
      progress: time,
      duration: duration || 2700, 
      lastWatched: Date.now(),
      season: selectedSeason,
      episode: selectedEpisode
    };

    if (index > -1) progress[index] = item;
    else progress.push(item);

    localStorage.setItem('watchProgress', JSON.stringify(progress));
    window.dispatchEvent(new Event('watchProgressUpdated'));

    if (time > (duration || 2700) * 0.98) {
        const tvProg = JSON.parse(localStorage.getItem('tv_progress') || '{}');
        const showSet = new Set(tvProg[id!] || []);
        showSet.add(`${selectedSeason}-${selectedEpisode}`);
        tvProg[id!] = Array.from(showSet);
        localStorage.setItem('tv_progress', JSON.stringify(tvProg));
        setWatchedEpisodes(new Set(tvProg[id!]));

        if (isBingeEnabled && !showBingeCountdown) {
            setShowBingeCountdown(true);
            setCountdown(10);
        }
    }
    window.dispatchEvent(new Event('storage'));
  }, [content, selectedSeason, selectedEpisode, id, isBingeEnabled, showBingeCountdown]);

  useEffect(() => {
    const handlePlayerMessages = (event: MessageEvent) => {
      try {
        const payload = typeof event.data === 'string' ? JSON.parse(event.data) : event.data;
        if (payload && (payload.type === 'PLAYER_EVENT' || payload.event)) {
          const data = payload.data || payload;
          if (data.event === 'timeupdate' || data.event === 'pause') {
            updateProgress(data);
          }
          if (data.event === 'ended') {
            if (isBingeEnabled) {
              setShowBingeCountdown(true);
              setCountdown(10);
            }
          }
        }
      } catch (e) {}
    };
    window.addEventListener('message', handlePlayerMessages);
    return () => window.removeEventListener('message', handlePlayerMessages);
  }, [updateProgress, isBingeEnabled]);

  const fetchSeasonDetails = useCallback(async (seasonNum: number) => {
    setSeasonDetails(null);
    try {
        const data = await fetchData(`/tv/${id}/season/${seasonNum}?api_key=${API_KEY}&language=en-US`, language);
        if (data) setSeasonDetails(data);
    } catch (e) { console.error(e); }
  }, [id, language]);

  useEffect(() => {
    const fetchContentDetails = async () => {
        if (!id) return;
        setLoading(true);
        try {
            const apiLang = 'en-US';
            const endpoint = `/tv/${id}?api_key=${API_KEY}&language=${apiLang}&append_to_response=credits,similar,recommendations,images,videos&include_image_language=en,null`;
            const data = await fetchData(endpoint, language);
            if (data) {
                setContent(data);
                setCast(data.credits?.cast?.slice(0, 15) || []);
                let recs = [...(data.recommendations?.results || []), ...(data.similar?.results || [])];
                setRecommendations(recs.filter(r => r.id !== Number(id) && !isForbidden(r, language)));

                const logo = data.images?.logos?.find((l: any) => l.file_path && (l.iso_639_1 === 'en' || !l.iso_639_1));
                if (logo) setLogoPath(logo.file_path);

                const trailer = data.videos?.results?.find((v: any) => v.type === 'Trailer' && v.site === 'YouTube');
                if (trailer) setTrailerKey(trailer.key);

                const tvProg = JSON.parse(localStorage.getItem('tv_progress') || '{}');
                setWatchedEpisodes(new Set(tvProg[id] || []));

                const progressData = JSON.parse(localStorage.getItem('watchProgress') || '[]');
                const saved = progressData.find((p: any) => p.id === data.id && p.type === 'tv');
                if (saved) {
                   setSelectedSeason(saved.season || 1);
                   setSelectedEpisode(saved.episode || 1);
                   setInitialProgress(saved.progress || 0);
                   fetchSeasonDetails(saved.season || 1);
                } else {
                   fetchSeasonDetails(1);
                }
            }
        } catch (error) { console.error(error); } finally { setLoading(false); }
    };
    fetchContentDetails();
    window.scrollTo(0, 0);
  }, [id, language, fetchSeasonDetails]);

  const handlePlayClick = (s?: number, e?: number) => {
    if (s) setSelectedSeason(s);
    if (e) setSelectedEpisode(e);
    setIsPlayerLoading(true);
    setIsPlayerModalOpen(true);
    setShowBingeCountdown(false);
    if (s && s !== selectedSeason) fetchSeasonDetails(s);
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-black"><Spinner /></div>;
  if (!content) return null;

  return (
    <div className="pb-32 bg-black min-h-screen text-white relative overflow-x-hidden" dir={language === 'ku' ? 'rtl' : 'ltr'}>
        <div className="fixed inset-0 pointer-events-none opacity-20 z-0">
          <img src={`${IMAGE_BASE_URL}${content.backdrop_path}`} className="w-full h-full object-cover blur-[120px]" alt="" />
        </div>

        <AnimatePresence>
            {isPlayerModalOpen && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 bg-black z-[200] flex flex-col items-center justify-center" dir="ltr">
                    <div className="w-full max-w-6xl flex items-center justify-between p-4 bg-black/50 backdrop-blur-xl border-b border-white/5">
                        <button onClick={() => setIsPlayerModalOpen(false)} className="header-btn"><X size={20} /></button>
                        <div className="text-center px-4">
                           <p className="text-red-600 font-black uppercase text-[10px] tracking-[0.2em]">{content.name}</p>
                           <p className="text-xs text-white font-bold">S{selectedSeason} • E{selectedEpisode}</p>
                        </div>
                        <button onClick={() => setShowSourceSwitcher(!showSourceSwitcher)} className="header-btn w-auto px-4 text-[9px] font-black">RELINK</button>
                    </div>
                    <div className="w-full max-w-6xl aspect-video relative bg-black border border-white/5 overflow-hidden shadow-2xl">
                        {isPlayerLoading && <div className="absolute inset-0 flex flex-col items-center justify-center bg-black z-10"><Spinner /></div>}
                        <iframe src={getSourceUrl(activeSource, id!, 'tv', selectedSeason, selectedEpisode, initialProgress)} allowFullScreen className="w-full h-full border-none pointer-events-auto" onLoad={() => setIsPlayerLoading(false)}></iframe>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {/* CINEMATIC NEURAL PORTAL HERO */}
        <div className="relative w-full h-[70vh] md:h-[90vh] overflow-hidden z-10 blur-line-mask" dir="ltr">
            <div className="absolute inset-0">
                {trailerKey ? (
                    <div className="absolute inset-0 scale-[1.4] pointer-events-none">
                        <iframe 
                            src={`https://www.youtube.com/embed/${trailerKey}?autoplay=1&mute=${isMuted ? 1 : 0}&loop=1&playlist=${trailerKey}&controls=0&modestbranding=1&rel=0&showinfo=0&iv_load_policy=3`} 
                            className="w-full h-full opacity-60 filter brightness-90" 
                            frameBorder="0" 
                            allow="autoplay"
                        />
                    </div>
                ) : (
                    <img src={`${IMAGE_BASE_URL}${content.backdrop_path}`} alt="" className="w-full h-full object-cover opacity-60" />
                )}

                {/* DECORATIVE LINE MASK (Matches Screenshot) */}
                <div className="absolute bottom-[20%] left-0 w-full h-px bg-cyan-400/40 blur-[2px] shadow-[0_0_20px_#22d3ee] z-20" />

                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-transparent"></div>
                <div className="absolute inset-x-0 bottom-0 h-48 bg-gradient-to-t from-black to-transparent backdrop-blur-lg" />
            </div>

            <div className={`absolute top-24 ${language === 'ku' ? 'left-6 md:left-20' : 'right-6 md:right-20'} z-30 flex items-center gap-2`}>
                {trailerKey && (
                    <button onClick={() => setIsMuted(!isMuted)} className="header-btn">
                        {isMuted ? <VolumeX size={20} /> : <Volume2 size={20} />}
                    </button>
                )}
                <button onClick={() => navigate(-1)} className="header-btn">
                    <ArrowLeft size={18} className={language === 'ku' ? 'rotate-180' : ''} />
                </button>
            </div>

            <div className={`absolute bottom-12 md:bottom-28 ${language === 'ku' ? 'right-0 text-right px-6 md:px-8 lg:px-20' : 'left-0 text-left px-6 md:px-8 lg:px-20'} z-20 flex flex-col items-start max-w-6xl`}>
                <div className="flex flex-wrap items-center gap-3 mb-6">
                    <div className="bg-cyan-600/20 border border-cyan-600/30 text-cyan-500 px-4 py-1.5 rounded-full flex items-center gap-1.5 text-[8px] md:text-[10px] font-black uppercase tracking-widest shadow-xl backdrop-blur-md"><Shield size={12} /> SECURE TV VAULT</div>
                    <button onClick={toggleBingeMode} className={`px-4 py-1.5 rounded-full flex items-center gap-2 text-[8px] md:text-[10px] font-black uppercase tracking-widest transition-all shadow-lg backdrop-blur-md ${isBingeEnabled ? 'bg-red-600 text-white border-red-500' : 'bg-white/10 text-gray-400 border border-white/10'}`}>
                      <Zap size={10} className={isBingeEnabled ? 'fill-white' : ''} /> {isBingeEnabled ? 'Binge Mode On' : 'Binge Mode Off'}
                    </button>
                </div>

                <div className="mb-10 w-full max-w-md md:max-w-xl">
                  {logoPath ? (
                    <motion.img 
                      initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} 
                      src={`${IMAGE_BASE_URL}${logoPath}`} alt={content.name} 
                      className="max-w-full h-auto max-h-32 md:max-h-64 object-contain drop-shadow-[0_15px_15px_rgba(0,0,0,0.8)]" 
                    />
                  ) : (
                    <motion.h1 initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} className="text-5xl md:text-9xl font-[1000] mb-6 uppercase italic tracking-tighter leading-[0.85] text-white drop-shadow-2xl">
                      {content.name}
                    </motion.h1>
                  )}
                </div>

                <div className="flex flex-wrap items-center gap-3 md:gap-5 mb-10">
                    <div className="flex items-center gap-1.5 bg-yellow-500/10 px-4 py-2 rounded-xl border border-yellow-500/20 shadow-lg backdrop-blur-md"><Star size={14} className="text-yellow-500 fill-current" /><span className="text-sm font-black text-yellow-500">{content.vote_average.toFixed(1)}</span></div>
                    <div className="flex items-center gap-1.5 bg-white/10 px-4 py-2 rounded-xl border border-white/10 shadow-lg backdrop-blur-md"><Calendar size={14} className="text-gray-400" /><span className="text-sm font-black text-gray-400">{content.first_air_date?.split('-')[0]}</span></div>
                </div>
                <div className="flex flex-wrap items-center gap-4">
                  <motion.button whileHover={{ scale: 1.05, y: -5 }} onClick={() => handlePlayClick()} className="flex items-center gap-4 bg-white text-black font-[1000] py-5 px-12 md:py-6 md:px-20 rounded-2xl md:rounded-[2rem] shadow-[0_20px_40px_rgba(255,255,255,0.2)] group">
                    <Play size={24} fill="black" />
                    <span className="text-lg md:text-2xl uppercase italic tracking-tighter">{language === 'ku' ? 'دەستپێکردن' : 'RESUME NODE'}</span>
                  </motion.button>
                </div>
            </div>
        </div>

        <div className="container mx-auto px-6 lg:px-20 py-16 md:py-24 relative z-10">
            <ColorMixtureDivider />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-16 md:gap-20">
                <div className="lg:col-span-2">
                    <div className="mb-20">
                        <div className="flex flex-col md:flex-row md:items-center justify-between mb-16 gap-6">
                            <div className="flex items-center gap-4">
                                <div className="p-4 bg-red-600 rounded-2xl shadow-2xl"><Clapperboard size={24} className="text-white" /></div>
                                <h2 className="text-3xl md:text-7xl font-[1000] uppercase italic tracking-tighter text-white">{language === 'ku' ? 'ئەڵقەکان' : 'ARCHIVE_NODES'}</h2>
                            </div>
                            <div className="flex flex-wrap items-center gap-4">
                                <div className="relative min-w-[200px]" dir="ltr">
                                    <select value={selectedSeason} onChange={(e) => { setSelectedSeason(Number(e.target.value)); fetchSeasonDetails(Number(e.target.value)); }} className="w-full bg-white/5 border-2 border-white/10 rounded-2xl px-6 py-4 text-white font-black uppercase appearance-none focus:border-red-600 outline-none shadow-2xl backdrop-blur-xl">
                                        {content.seasons?.filter((s: any) => s.season_number > 0).map((s: any) => <option key={s.id} value={s.season_number} className="bg-[#111]">{language === 'ku' ? 'وەرزی' : 'Season'} {s.season_number}</option>)}
                                    </select>
                                    <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-red-600 pointer-events-none" size={20} />
                                </div>
                            </div>
                        </div>

                        {!seasonDetails ? <div className="flex justify-center py-20"><Spinner /></div> : (
                            <div className="grid grid-cols-1 gap-6">
                                {seasonDetails.episodes.map((ep) => {
                                    const epKey = `${selectedSeason}-${ep.episode_number}`;
                                    const isWatched = watchedEpisodes.has(epKey);
                                    const isActive = selectedEpisode === ep.episode_number && isPlayerModalOpen;

                                    return (
                                        <motion.div key={ep.id} whileHover={{ x: 10 }} onClick={() => handlePlayClick(selectedSeason, ep.episode_number)} className={`group relative bg-white/[0.02] border p-5 md:p-8 rounded-[3rem] flex flex-col md:flex-row items-center gap-8 cursor-pointer transition-all overflow-hidden ${isActive ? 'border-red-600 bg-red-600/[0.08]' : 'border-white/5'} ${isWatched && !isActive ? 'opacity-40 grayscale-[0.5]' : ''}`}>
