const App: React.FC = () => {
  const { language, t } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [scrolled, setScrolled] = useState(false);
  const mainRef = useRef<HTMLElement>(null);

  // SYSTEM BOOT: Extended Architecture Sync
  useEffect(() => {
    const root = document.documentElement;
    const sysParams = [
        { key: 'text', def: '1.0' },
        { key: 'card', def: '1.0' },
        { key: 'btn', def: '1.0' },
        { key: 'radius', def: '1.0' },
        { key: 'motion', def: '1.0' },
        { key: 'contrast', def: '1.0' },
        { key: 'blur', def: '20px' },
        { key: 'glow', def: '1.0' },
        { key: 'scanlines', def: '0' },
        { key: 'weight', def: '500' },
        { key: 'accent', def: '#e50914' },
        { key: 'grain', def: '0' },
        { key: 'pulse', def: '1.0' }
    ];

    sysParams.forEach(p => {
        const val = localStorage.getItem(`flkrd_${p.key}_scale`) || p.def;

        if (p.key === 'accent') root.style.setProperty('--brand-accent', val);
        else if (p.key === 'blur') root.style.setProperty('--blur-intensity', val);
        else if (p.key === 'glow') root.style.setProperty('--glow-strength', val);
        else if (p.key === 'scanlines') root.style.setProperty('--scanline-opacity', val);
        else if (p.key === 'weight') root.style.setProperty('--font-weight', val);
        else if (p.key === 'grain') root.style.setProperty('--ui-grain', val);
        else if (p.key === 'pulse') root.style.setProperty('--pulse-speed', `${val}s`);
        else root.style.setProperty(`--${p.key}-scale`, val);
    });

    const requestHardwarePermissions = async () => {
      try {
        if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
           const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
           stream.getTracks().forEach(track => track.stop());
           console.log("NEURAL_HARDWARE: LINK_ESTABLISHED");
        }
      } catch (err) {
        console.warn("NEURAL_HARDWARE: LINK_RESTRICTED", err);
      }
    };
    requestHardwarePermissions();
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 8000); 
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const handleScroll = () => {
        if (mainRef.current) setScrolled(mainRef.current.scrollTop > 10);
    };
    const mainEl = mainRef.current;
    if (mainEl) mainEl.addEventListener('scroll', handleScroll);
    return () => mainEl?.removeEventListener('scroll', handleScroll);
  }, [loading]);

  if (loading) return <SplashScreen />;

  return (
    <div className="bg-black min-h-screen text-white" dir={language === 'ku' ? 'rtl' : 'ltr'}>
      <HashRouter>
        <div className="flex">
          <Sidebar />
          <div className="flex-1 flex flex-col min-w-0">
            <Header scrolled={scrolled} />
            <main ref={mainRef} className="flex-1 overflow-y-auto">
              <Routes>
                <Route path="/" element={<HomePage />} />
                <Route path="/tv" element={<TVShowsPage />} />
                <Route path="/dubbed" element={<DubbedMoviesPage />} />
                <Route path="/discover" element={<DiscoverPage />} /><Route path="/discover/:selection" element={<DiscoverPage />} />
                <Route path="/shorts" element={<ShortsPage />} />
                <Route path="/studios" element={<StudiosListPage />} /><Route path="/studio/:id/:name" element={<StudioPage />} />
                <Route path="/details/movie/:id" element={<DetailPage />} /><Route path="/details/tv/:id" element={<TVDetailPage />} />
                <Route path="/dubbed-details/:id" element={<DubbedDetailPage />} />
                <Route path="/search" element={<SearchPage />} /><Route path="/my-list" element={<MyListPage />} />
                <Route path="/continue-watching" element={<ContinueWatchingPage />} />
                <Route path="/profile" element={<ProfilePage />} />
              </Routes>
            </main>
          </div>
          <MobileNav />
        </div>
        <ContinueWatchingPortal />
        <WelcomeNotificationPrompt />
      </HashRouter>
    </div>
  );
};

