import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Cpu, Trash2, ShieldCheck, RefreshCw, Activity, Type, Layout, MousePointer2, BoxSelect, RotateCcw, Camera, Mic, Sparkles, Zap, Wind, Eye, Volume2, Fingerprint, Layers, Monitor, Bold, Waves, Timer } from 'lucide-react';
