import Spinner from '../components/Spinner';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';
import { getRankedSources, getSourceUrl } from '../utils/playerSourceUtils';

const ColorMixtureDivider: React.FC = () => {
    return (
        <div className="relative w-full h-12 md:h-16 my-8 md:my-12 overflow-hidden rounded-[2rem] border border-white/5 bg-white/[0.01] backdrop-blur-xl">
            <motion.div 
                animate={{ 
                    x: [0, 100, 0],
                    opacity: [0.3, 0.6, 0.3]
                }}
                transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
                className="absolute -left-20 top-1/2 -translate-y-1/2 w-64 h-32 bg-red-600/40 rounded-full blur-[60px]"
            />
            <motion.div 
                animate={{ 
                    x: [0, -100, 0],
                    opacity: [0.2, 0.5, 0.2]
                }}
                transition={{ duration: 12, repeat: Infinity, ease: "linear" }}
                className="absolute -right-20 top-1/2 -translate-y-1/2 w-80 h-32 bg-purple-600/30 rounded-full blur-[70px]"
            />
            {/* NEURAL ARC SKETCH */}
            <div className="neural-curve bottom-0 scale-y-[-1] opacity-60" />
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent"></div>
        </div>
    );
};

const DetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t, language } = useTranslation();
  const { addNotification } = useNotification();
  const [content, setContent] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [isPlayerLoading, setIsPlayerLoading] = useState(true);
  const [cast, setCast] = useState<CastMember[]>([]);
  const [recommendations, setRecommendations] = useState<Content[]>([]);
  const [isInMyList, setIsInMyList] = useState(false);
  const [isPlayerModalOpen, setIsPlayerModalOpen] = useState(false);
  const [activeSource, setActiveSource] = useState('Vidking');
  const [showSourceSwitcher, setShowSourceSwitcher] = useState(false);
  const [logoPath, setLogoPath] = useState<string | null>(null);
  const [trailerKey, setTrailerKey] = useState<string | null>(null);
  const [isMuted, setIsMuted] = useState(true);

  useEffect(() => {
    const fetchContentDetails = async () => {
        if (!id) return;
        setLoading(true);
        try {
            const apiLang = 'en-US';
            const endpoint = `/movie/${id}?api_key=${API_KEY}&language=${apiLang}&append_to_response=credits,similar,recommendations,images,videos&include_image_language=en,null`;
            const data = await fetchData(endpoint, language);
            if (data) {
                setContent(data);
                setCast(data.credits?.cast?.slice(0, 10) || []);
                let recs = [...(data.recommendations?.results || []), ...(data.similar?.results || [])];
                setRecommendations(recs.filter(r => r.id !== Number(id) && !isForbidden(r, language)));

                const logo = data.images?.logos?.find((l: any) => l.file_path && (l.iso_639_1 === 'en' || !l.iso_639_1));
                if (logo) setLogoPath(logo.file_path);

                const trailer = data.videos?.results?.find((v: any) => v.type === 'Trailer' && v.site === 'YouTube');
                if (trailer) setTrailerKey(trailer.key);
            }
        } catch (error) { console.error(error); } finally { setLoading(false); }
    };
    fetchContentDetails();
    window.scrollTo(0, 0);
  }, [id, language]);

  const handlePlayClick = () => {
    setIsPlayerLoading(true);
    setIsPlayerModalOpen(true);
  };

  const handleToggleMyList = () => {
    if (!content) return;
    let myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
    const index = myList.findIndex(item => item.id === content.id);
    if (index > -1) {
      myList.splice(index, 1);
      setIsInMyList(false);
    } else {
      myList.push({ id: content.id, media_type: 'movie', title: content.title || '', poster_path: content.poster_path });
      setIsInMyList(true);
    }
    localStorage.setItem('myList', JSON.stringify(myList));
    window.dispatchEvent(new Event('storage'));
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-black"><Spinner /></div>;
  if (!content) return null;

  return (
    <div className="pb-40 bg-black min-h-screen text-white relative overflow-x-hidden" dir={language === 'ku' ? 'rtl' : 'ltr'}>
        <div className="fixed inset-0 pointer-events-none z-0">
          <img src={`${IMAGE_BASE_URL}${content.backdrop_path}`} className="w-full h-full object-cover blur-[100px] opacity-30 scale-125" alt="" />
          <div className="absolute inset-0 bg-gradient-to-b from-black/60 via-transparent to-black"></div>
        </div>

        <AnimatePresence>
            {isPlayerModalOpen && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 bg-black z-[200] flex flex-col items-center justify-center backdrop-blur-3xl" dir="ltr">
                    <div className="w-full max-w-7xl flex items-center justify-between p-4 md:p-6 bg-black/40 backdrop-blur-xl border-b border-white/5">
                        <button onClick={() => setIsPlayerModalOpen(false)} className="header-btn">
                          <X size={20} />
                        </button>
                        <h2 className="text-sm font-bold uppercase italic line-clamp-1">{content.title}</h2>
                        <button onClick={() => setShowSourceSwitcher(!showSourceSwitcher)} className="header-btn text-[10px] font-black">RELINK</button>
                    </div>
                    <div className="w-full max-w-7xl aspect-video relative bg-black shadow-2xl border border-white/10 overflow-hidden">
                        {isPlayerLoading && <div className="absolute inset-0 flex flex-col items-center justify-center bg-black z-10"><Spinner /></div>}
                        <iframe src={getSourceUrl(activeSource, id!, 'movie')} allowFullScreen className="w-full h-full border-none" onLoad={() => setIsPlayerLoading(false)}></iframe>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {/* FULL SCREEN HERO SECTION WITH BACKDROP FIX */}
        <div className="relative w-full h-screen overflow-hidden z-10 blur-line-mask" dir="ltr">
            <div className="absolute inset-0">
                {trailerKey ? (
                    <div className="absolute inset-0 scale-[1.3] pointer-events-none transition-transform duration-1000">
                        <iframe 
                            src={`https://www.youtube.com/embed/${trailerKey}?autoplay=1&mute=${isMuted ? 1 : 0}&loop=1&playlist=${trailerKey}&controls=0&modestbranding=1&rel=0&showinfo=0&iv_load_policy=3&disablekb=1&enablejsapi=1`} 
                            className="w-full h-full opacity-80 filter contrast-125 saturate-110" 
                            frameBorder="0" 
                            allow="autoplay"
                        />
                    </div>
                ) : (
                    <img src={`${IMAGE_BASE_URL}${content.backdrop_path}`} alt="" className="w-full h-full object-cover opacity-85" />
                )}

                {/* NEURAL CURVE ARC MASK */}
                <div className="neural-curve bottom-[8%]" />

                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/10 to-transparent"></div>
                <div className="absolute inset-x-0 bottom-0 h-80 bg-gradient-to-t from-black to-transparent backdrop-blur-xl" />
            </div>

            <div className={`absolute top-28 ${language === 'ku' ? 'left-6 md:left-20' : 'right-6 md:right-20'} z-30 flex items-center gap-3`}>
                {trailerKey && (
                    <button onClick={() => setIsMuted(!isMuted)} className="header-btn">
                        {isMuted ? <VolumeX size={20} /> : <Volume2 size={20} />}
                    </button>
                )}
                <button onClick={() => navigate(-1)} className="header-btn">
                    <ArrowLeft size={18} className={`${language === 'ku' ? 'rotate-180' : ''}`} />
                </button>
            </div>

            <div className={`absolute bottom-24 md:bottom-40 ${language === 'ku' ? 'right-0 text-right px-6 md:px-20' : 'left-0 text-left px-6 md:px-20'} z-20 flex flex-col items-start max-w-6xl`}>
                <div className="flex flex-wrap items-center gap-3 mb-8">
                    <div className="bg-red-600/90 text-white px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-[0.3em] shadow-accent flex items-center gap-2 animate-pulse-neural border border-white/20">
                        <ShieldCheck size={16} /> LIVE NEURAL NODE ALPHA
                    </div>
                </div>

                <div className="mb-12 w-full max-w-2xl">
                  {logoPath ? (
                    <motion.img 
                      initial={{ opacity: 0, y: 30 }} 
                      animate={{ opacity: 1, y: 0 }} 
                      src={`${IMAGE_BASE_URL}${logoPath}`} 
                      alt={content.title} 
                      className="max-w-full h-auto max-h-48 md:max-h-80 object-contain drop-shadow-[0_25px_35px_rgba(0,0,0,0.95)]" 
                    />
                  ) : (
                    <motion.h1 initial={{ opacity: 0, y: 40 }} animate={{ opacity: 1, y: 0 }} className="text-6xl md:text-9xl font-[1000] uppercase italic tracking-tighter leading-[0.8] text-white drop-shadow-2xl">
                      {content.title}
                    </motion.h1>
                  )}
                </div>

                <div className="flex flex-wrap items-center gap-5 mb-12">
                    <div className="flex items-center gap-2 bg-yellow-500/20 px-6 py-3 rounded-2xl border border-yellow-500/30 backdrop-blur-3xl shadow-xl">
                        <Star size={20} className="text-yellow-500 fill-current" />
                        <span className="text-xl font-black text-yellow-500">{content.vote_average.toFixed(1)}</span>
                    </div>
                    <div className="flex items-center gap-2 bg-white/10 px-6 py-3 rounded-2xl border border-white/10 backdrop-blur-3xl text-gray-300 shadow-xl">
                        <Timer size={20} />
                        <span className="text-xl font-black">{content.runtime}m</span>
                    </div>
                    <div className="flex items-center gap-2 bg-white/10 px-6 py-3 rounded-2xl border border-white/10 backdrop-blur-3xl text-gray-300 shadow-xl">
                        <Calendar size={20} />
                        <span className="text-xl font-black">{content.release_date?.split('-')[0]}</span>
                    </div>
                </div>

                <div className="flex flex-wrap items-center gap-6">
                    <motion.button whileHover={{ scale: 1.05, y: -5 }} onClick={handlePlayClick} className="flex items-center gap-6 bg-white text-black font-[1000] py-6 px-16 md:px-24 rounded-[2.5rem] shadow-[0_40px_80px_rgba(255,255,255,0.25)] transition-all group">
                        <Play size={32} fill="black" />
                        <span className="text-xl md:text-4xl uppercase italic tracking-tighter">START ARCHIVE</span>
                    </motion.button>
                    <button onClick={handleToggleMyList} className="header-btn w-[80px] h-[80px] rounded-[2rem]">
                        {isInMyList ? <Check size={32} className="text-green-400" /> : <Plus size={32} />}
                    </button>
                </div>
            </div>
        </div>

        <div className="container mx-auto px-6 lg:px-20 relative z-10 -mt-20">
            <ColorMixtureDivider />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-16 md:gap-24 py-20">
                <div className="lg:col-span-2 space-y-24">
                    <div className="bg-white/[0.03] border border-white/10 p-12 md:p-20 rounded-[4.5rem] backdrop-blur-[120px] shadow-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-80 h-80 bg-red-600/10 blur-[100px] -z-10" />
                        <div className="flex items-center gap-5 mb-12">
                            <div className="w-2 h-12 bg-red-600 rounded-full shadow-accent"></div>
                            <h3 className="text-[14px] font-black uppercase tracking-[0.6em] text-gray-500 italic">LOG_ARCHIVE_DATA</h3>
                        </div>
                        <p className="text-gray-200 text-2xl md:text-5xl leading-tight italic font-bold">
                            {content.overview}
                        </p>
                    </div>

                    {cast.length > 0 && (
                      <div className="space-y-16">
                        <div className="flex items-center gap-8"><h2 className="text-5xl md:text-8xl font-[1000] uppercase italic tracking-tighter text-white">BIOMETRIC_FEEDS</h2><div className="h-[2px] flex-grow bg-white/5 rounded-full"></div></div>
                        <div className="grid grid-cols-3 md:grid-cols-5 gap-8 md:gap-12">
                          {cast.map(person => (
                            <div key={person.id} className="group cursor-pointer">
                              <div className="aspect-[3/4] rounded-[3rem] overflow-hidden mb-6 border border-white/10 shadow-2xl relative">
                                <img src={person.profile_path ? `${IMAGE_BASE_URL}${person.profile_path}` : 'https://i.imgur.com/4HoT8Yf.png'} alt="" className="w-full h-full object-cover grayscale transition-all duration-1000 group-hover:grayscale-0 group-hover:scale-110" />
                              </div>
                              <p className="text-sm font-black uppercase italic truncate text-center text-white drop-shadow-md">{person.name}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}
                </div>

                <div className="space-y-12">
                    <div className="bg-white/[0.03] border border-white/10 p-12 rounded-[4rem] shadow-2xl backdrop-blur-3xl sticky top-28">
                        <h3 className="text-[11px] font-black uppercase tracking-[0.5em] mb-12 text-gray-500 italic">TRANSMISSION_SOURCE</h3>
                        <div className="grid grid-cols-2 gap-8">
                           {content.production_companies?.filter((c: any) => c.logo_path).slice(0, 4).map((company: any) => (
                               <div key={company.id} className="aspect-square bg-black/60 rounded-[2.5rem] p-8 flex items-center justify-center hover:bg-white transition-all duration-500 group/comp border border-white/10 shadow-inner">
                                   <img src={`${IMAGE_BASE_URL_LOGO}${company.logo_path}`} alt="" className="max-w-full max-h-full object-contain filter brightness-0 invert group-hover/comp:invert-0" />
                               </div>
                           ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
  );
};

export default DetailPage;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Cpu, Trash2, ShieldCheck, RefreshCw, Activity, Type, Layout, MousePointer2, BoxSelect, RotateCcw, Camera, Mic, Sparkles, Zap, Wind, Eye, Volume2, Fingerprint, Layers, Monitor, Bold, Waves, Timer, Radio, Maximize, ZoomIn } from 'lucide-react';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';
import { APP_VERSION } from '../constants';

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const ACCENT_PRESETS = [
    { name: 'RAGE', color: '#e50914' },
    { name: 'NEON', color: '#22d3ee' },
    { name: 'VOID', color: '#a855f7' },
    { name: 'GOLD', color: '#f59e0b' },
    { name: 'ZEN', color: '#10b981' }
];

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose }) => {
  const { t, language, setLanguage } = useTranslation();
  const { addNotification } = useNotification();

  // LIVE ARCHITECTURE STATE
  const [textScale, setTextScale] = useState(() => Number(localStorage.getItem('flkrd_text_scale') || '1.0'));
  const [cardScale, setCardScale] = useState(() => Number(localStorage.getItem('flkrd_card_scale') || '1.0'));
  const [btnScale, setBtnScale] = useState(() => Number(localStorage.getItem('flkrd_btn_scale') || '1.0'));
  const [radiusScale, setRadiusScale] = useState(() => Number(localStorage.getItem('flkrd_radius_scale') || '1.0'));
  const [motionScale, setMotionScale] = useState(() => Number(localStorage.getItem('flkrd_motion_scale') || '1.0'));
  const [contrastScale, setContrastScale] = useState(() => Number(localStorage.getItem('flkrd_contrast_scale') || '1.0'));
  const [accent, setAccent] = useState(() => localStorage.getItem('flkrd_accent_scale') || '#e50914');

  // OPTICS TOOLS
  const [blurAmount, setBlurAmount] = useState(() => Number(localStorage.getItem('flkrd_blur_scale')?.replace('px','') || '20'));
  const [glowStrength, setGlowStrength] = useState(() => Number(localStorage.getItem('flkrd_glow_scale') || '1.0'));
  const [scanlines, setScanlines] = useState(() => localStorage.getItem('flkrd_scanlines_scale') === '1');
  const [fontWeight, setFontWeight] = useState(() => Number(localStorage.getItem('flkrd_weight_scale') || '500'));
  const [uiGrain, setUiGrain] = useState(() => Number(localStorage.getItem('flkrd_grain_scale') || '0.05'));
  const [pulseSpeed, setPulseSpeed] = useState(() => Number(localStorage.getItem('flkrd_pulse_scale') || '1.0'));
  const [imageZoom, setImageZoom] = useState(() => Number(localStorage.getItem('flkrd_zoom_scale') || '1.0'));

  const [hapticEnabled, setHapticEnabled] = useState(true);

  // REAL-TIME INJECTION ENGINE
  const updateSystemVar = (key: string, val: string | number) => {
    const root = document.documentElement;
    const cssKey = key === 'accent' ? `--brand-accent` : `--${key}-scale`;

    if (key === 'blur') root.style.setProperty('--blur-intensity', `${val}px`);
    else if (key === 'glow') root.style.setProperty('--glow-strength', val.toString());
    else if (key === 'scanlines') root.style.setProperty('--scanline-opacity', val ? '1' : '0');
    else if (key === 'weight') root.style.setProperty('--font-weight', val.toString());
    else if (key === 'grain') root.style.setProperty('--ui-grain', val.toString());
    else if (key === 'pulse') root.style.setProperty('--pulse-speed', `${val}s`);
    else if (key === 'zoom') root.style.setProperty('--image-zoom', val.toString());
    else root.style.setProperty(cssKey, val.toString());

    localStorage.setItem(`flkrd_${key}_scale`, val.toString());
  };

  const handleReset = () => {
    const defaults = { text: 1.0, card: 1.0, btn: 1.0, radius: 1.0, motion: 1.0, contrast: 1.0, accent: '#e50914', blur: 20, glow: 1.0, scanlines: 0, weight: 500, grain: 0.05, pulse: 1.0, zoom: 1.0 };
    setTextScale(1.0); setCardScale(1.0); setBtnScale(1.0); setRadiusScale(1.0); setMotionScale(1.0); setContrastScale(1.0); setAccent('#e50914');
    setBlurAmount(20); setGlowStrength(1.0); setScanlines(false); setFontWeight(500); setUiGrain(0.05); setPulseSpeed(1.0); setImageZoom(1.0);
    Object.entries(defaults).forEach(([k, v]) => updateSystemVar(k, v));
    addNotification({ type: 'info', title: 'System Restore', message: 'Mainframe protocols normalized.' });
  };

  const ScaleSlider = ({ icon, label, value, setter, id, min = 0.5, max = 1.5, step = 0.05, suffix = "%" }: any) => (
    <div className="p-4 bg-white/[0.03] border border-white/5 rounded-2xl group hover:border-white/10 transition-all">
        <div className="flex items-center justify-between mb-3">
            <div className="flex items-center gap-2">
                <div className="text-gray-400 group-hover:text-accent transition-colors">{icon}</div>
                <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">{label}</span>
            </div>
            <span className="text-[9px] font-black text-accent bg-accent/10 px-2 py-0.5 rounded border border-accent/20">{suffix === '%' ? Math.round(value * 100) : value}{suffix}</span>
        </div>
        <input 
            type="range" min={min} max={max} step={step} value={value}
            onChange={(e) => {
                const val = parseFloat(e.target.value);
                setter(val);
                updateSystemVar(id, val);
            }}
            className="w-full h-1 bg-white/10 rounded-full appearance-none cursor-pointer accent-red-600"
        />
    </div>
  );

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
          onClick={onClose}
          className="fixed inset-0 bg-black/95 backdrop-blur-xl z-[100] flex items-end md:items-center justify-center p-4"
        >
          <motion.div
            initial={{ y: 100, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 100, opacity: 0 }}
            onClick={e => e.stopPropagation()}
            className="w-full max-w-sm bg-[#080808] border border-white/10 rounded-[3rem] overflow-hidden shadow-2xl flex flex-col"
          >
            <div className="h-1.5 w-full bg-gradient-to-r from-accent to-black" style={{ backgroundColor: accent }} />

            <div className="p-6 max-h-[85vh] overflow-y-auto scrollbar-hide">
              <div className="flex items-center justify-between mb-8 px-2">
                <div>
                  <h2 className="text-2xl font-black uppercase italic tracking-tighter text-white">Terminal</h2>
                  <p className="text-[9px] font-black text-gray-500 uppercase tracking-widest flex items-center gap-1.5 mt-1">
                    <Activity size={10} className="text-accent animate-pulse" /> NEURAL_ARCH_LINK
                  </p>
                </div>
                <button onClick={onClose} className="header-btn">
                  <X size={20} />
                </button>
              </div>

              <div className="space-y-8">
                {/* COLOR MATRIX */}
                <div>
                    <p className="text-[9px] font-black text-gray-600 uppercase tracking-[0.4em] mb-4 px-2">Color Matrix</p>
                    <div className="flex gap-2 px-2 overflow-x-auto scrollbar-hide pb-2">
                        {ACCENT_PRESETS.map(p => (
                            <button 
                                key={p.name} 
                                onClick={() => { setAccent(p.color); updateSystemVar('accent', p.color); }}
                                className={`flex-shrink-0 w-10 h-10 rounded-full border-2 transition-all flex items-center justify-center ${accent === p.color ? 'border-white scale-110 shadow-lg' : 'border-transparent opacity-60'}`}
                                style={{ backgroundColor: p.color }}
                            >
                                {accent === p.color && <Sparkles size={14} className="text-white" />}
                            </button>
                        ))}
                    </div>
                </div>

                {/* ARCHITECTURE */}
                <div>
                  <div className="flex items-center justify-between mb-4 px-2">
                    <p className="text-[9px] font-black text-gray-600 uppercase tracking-[0.4em]">Architecture</p>
                    <button onClick={handleReset} className="text-[8px] font-black text-red-500 uppercase flex items-center gap-1 hover:text-white transition-colors">
                        <RotateCcw size={10}/> RESET
                    </button>
                  </div>
                  <div className="grid grid-cols-1 gap-3">
                    <ScaleSlider icon={<Type size={14}/>} label="Neural Text" id="text" value={textScale} setter={setTextScale} />
                    <ScaleSlider icon={<Layout size={14}/>} label="Archive Density" id="card" value={cardScale} setter={setCardScale} />
                    <ScaleSlider icon={<MousePointer2 size={14}/>} label="Action scale" id="btn" value={btnScale} setter={setBtnScale} />
                    <ScaleSlider icon={<BoxSelect size={14}/>} label="Node Radius" id="radius" value={radiusScale} setter={setRadiusScale} />
                  </div>
                </div>

                {/* OPTICS */}
                <div>
                    <p className="text-[9px] font-black text-gray-600 uppercase tracking-[0.4em] mb-4 px-2">Optics & Modulation</p>
                    <div className="grid grid-cols-1 gap-3">
                        <ScaleSlider icon={<Layers size={14}/>} label="Glass Blur" id="blur" value={blurAmount} setter={setBlurAmount} min={0} max={100} suffix="px" />
                        <ScaleSlider icon={<Zap size={14}/>} label="Neon Fidelity" id="glow" value={glowStrength} setter={setGlowStrength} min={0} max={2.0} />
                        <ScaleSlider icon={<ZoomIn size={14}/>} label="Neural Zoom" id="zoom" value={imageZoom} setter={setImageZoom} min={0.8} max={1.4} step={0.01} suffix="" />

                        <div className="flex items-center justify-between p-4 bg-white/[0.03] border border-white/5 rounded-2xl group hover:border-white/10">
                            <div className="flex items-center gap-2">
                                <Waves size={14} className="text-gray-400 group-hover:text-accent" />
                                <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">UI Grain Intensity</span>
                            </div>
