import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Plus, Check, Play } from 'lucide-react';
import { Content, WatchProgress, MyListItem } from '../types';
import { fetchData } from '../services/tmdbService';
import { IMAGE_BASE_URL_POSTER } from '../constants';
import Spinner from './Spinner';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';

interface RowProps {
  title: string;
  fetchUrl?: string;
  type?: 'movie' | 'tv';
  items?: (Content | WatchProgress | MyListItem)[];
  isProgressRow?: boolean;
}

const Row: React.FC<RowProps> = ({ title, fetchUrl, type, items, isProgressRow }) => {
  const [content, setContent] = useState<(Content | WatchProgress | MyListItem)[]>([]);
  const [loading, setLoading] = useState(true);
  const [myListIds, setMyListIds] = useState<Set<number>>(new Set());

  const navigate = useNavigate();
  const { language, t } = useTranslation();
  const { addNotification } = useNotification();

  const updateMyListIds = useCallback(() => {
    const myList = JSON.parse(localStorage.getItem('myList') || '[]');
    setMyListIds(new Set(myList.map((item: any) => item.id)));
  }, []);

  useEffect(() => {
    const loadInitialData = async () => {
        updateMyListIds();
        if (items) {
          setContent(items);
          setLoading(false);
        } else if (fetchUrl) {
          setLoading(true);
          const data = await fetchData(`${fetchUrl}${fetchUrl.includes('?') ? '&' : '?'}page=1`, language);
          if (data && Array.isArray(data)) setContent(data);
          setLoading(false);
        }
    };
    loadInitialData();
  }, [fetchUrl, items, language, updateMyListIds]);

  const handleToggleMyList = (e: React.MouseEvent, item: any, mediaType: 'movie' | 'tv') => {
    e.stopPropagation();
    let myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
    const index = myList.findIndex(i => i.id === item.id);
    if (index > -1) myList.splice(index, 1);
    else myList.push({ id: item.id, media_type: mediaType, title: item.title || item.name || '', poster_path: item.poster_path });
    localStorage.setItem('myList', JSON.stringify(myList));
    updateMyListIds();
    addNotification({ type: 'success', title: 'Vault', message: 'Archive synchronized.' });
  };

  if (loading) return <div className="h-32 flex items-center justify-center"><Spinner size="sm" /></div>;
  if (!content || content.length === 0) return null;

  return (
    <div className="mb-10 px-4 md:px-8 relative z-20 overflow-hidden">
      <div className="flex items-center justify-between mb-4">
          <h2 className="text-sm md:text-xl font-black uppercase italic tracking-tighter text-white flex items-center gap-3">
              <span className="w-1 h-5 bg-red-600 rounded-full shadow-[0_0_15px_#e50914]"></span>
              {title}
          </h2>
      </div>

      <div className="relative group">
        <div className="flex overflow-x-scroll scrollbar-hide space-x-4 py-2">
          {content.map((item, index) => {
              const mediaType = (item as Content).media_type || (item as WatchProgress).type || type || 'movie';
              if (!item.poster_path) return null;
              const isAdded = myListIds.has(item.id);
              const progressPct = 'progress' in item ? (item.progress / (item.duration || 1)) * 100 : 0;

              return (
              <motion.div
                key={`${item.id}-${index}`}
                onClick={() => navigate(`/details/${mediaType}/${item.id}`)}
                className="flex-shrink-0 movie-card group/card relative cursor-pointer shadow-2xl transition-all duration-300 overflow-hidden border border-white/5 md:group-hover/card:border-red-600/50"
                whileTap={{ scale: 0.95 }}
                style={{ aspectRation: '2/3' }}
              >
                  <img
                    src={`${IMAGE_BASE_URL_POSTER}${item.poster_path}`}
                    alt=""
                    className="object-cover w-full h-full transition-transform duration-700 md:group-hover/card:scale-110 image-node-fit"
                    loading="lazy"
                  />

                  <div className="absolute top-2 right-2 opacity-0 group-hover/card:opacity-100 transition-opacity z-30">
                      {!isProgressRow && (
                        <button
                          onClick={(e) => handleToggleMyList(e, item, mediaType as 'movie' | 'tv')}
                          className={`p-2 rounded-xl transition-all ${isAdded ? 'bg-red-600 text-white shadow-[0_0_10px_#e50914]' : 'bg-black/60 text-white hover:bg-red-600'}`}
                        >
                          {isAdded ? <Check size={14} strokeWidth={4} /> : <Plus size={14} strokeWidth={4} />}
                        </button>
                      )}
                  </div>

                  {progressPct > 0 && (
                      <div className="absolute bottom-0 left-0 right-0 h-1 bg-black/60 z-20">
                          <div className="h-full bg-red-600" style={{ width: `${progressPct}%` }} />
                      </div>
                  )}

                  <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent opacity-0 md:group-hover/card:opacity-100 transition-all flex flex-col justify-end p-4">
                      <div className="flex items-center gap-2">
                          <div className="bg-red-600 p-1.5 rounded-full"><Play size={10} fill="white" className="ml-0.5" /></div>
                          <span className="text-[10px] font-black uppercase tracking-widest text-white italic">Stream</span>
                      </div>
                  </div>
              </motion.div>
            )}
          )}
        </div>
      </div>
    </div>
  );
};

export default Row;

